// // This module implements a 7-bit binary counter that counts down when the up_down signal is high and counts up when the up_down signal is low.
module binary_up_down_counter(
    input       clk,
    input       rst,
    input       up_down,
    output reg [6:0] count
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 7'b0000000;
        end
        else if (up_down) begin
            count <= count + 1'b1;
        end
        else begin
            count <= count - 1'b1;
        end
    end

endmodule
